import android.content.Context
import javax.inject.Inject
 
class AuthenticationManager @Inject constructor(context: Context) {
    private val sharedPreferences = context.getSharedPreferences("app_settings", Context.MODE_PRIVATE)
    
    fun saveUserIdAndToken(userID: String, token:String){
        with (sharedPreferences.edit()) {  // Shared Preferences Editor is created here to edit the shared preferences file for writing data back into it later on  
            putString("USER_ID", userID)     // Saving User ID and Token in preference manager as a string pair   
            putString("TOKEN","Bearer $token") 
            
        }.apply()      // Applying the changes to Shared Preferences file using apply method  
        
       println ("UserID:$userID, saved successfully and Token : Bearer ${sharedPreferences.getString("USER_ID",null)} ")    // Prints out user ID which has been stored in shared preferences 
     }     
       
          fun getStoredToken(): String? {   // Function to retrieve the token from Shared Preferences file if it exists, else return null (default value)      
            val defaultValue:String? =null    // Default Value is set as Null because we are expecting a non-empty string in our preferences 
             println("Token : ${sharedPreferences.getString("TOKEN",defaultValue)}")   // Prints out the token which has been stored from shared preference file if it exists, else prints default value   
            return null     // Returns Token or Default Value (if any) as a String 
        }     
}